/**
 * Generate AviationStack firewall config.
 *
 * Data source: https://aviationstack.com/documentation
 *
 * AviationStack authenticates with an access key passed as the
 * `access_key` query parameter on every request.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://aviationstack.com/documentation";
// Format: 32 hex chars
const PLACEHOLDER_VALUE = "c0ffeesafelocal5afe10ca1c0ffeesa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from AviationStack API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:aviationstack",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const aviationstackFirewall = {",
    '  name: "aviationstack",',
    '  description: "AviationStack API",',
    "  placeholders: {",
    `    AVIATIONSTACK_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.aviationstack.com",',
    "      auth: {",
    "        query: {",
    '          access_key: "${{ secrets.AVIATIONSTACK_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating AviationStack firewall config...");
  const ts = generateTypeScript();
  writeOutput("aviationstack", ts, import.meta.dirname);
}
